```java
static Result<Integer> safeDivide(int a, int b) {
    if (b == 0) return Result.failure("Division by zero");
    return Result.success(a / b);
}

static Result<Integer> parseInt(String s) {
    try {
        return Result.success(Integer.parseInt(s));
    } catch (NumberFormatException e) {
        return Result.failure("Not a number: " + s);
    }
}

public static void main(String[] args) {
    System.out.println(safeDivide(10, 2));         // Success(5)
    System.out.println(safeDivide(10, 0));         // Failure(Division by zero)
    System.out.println(parseInt("42"));            // Success(42)
    System.out.println(parseInt("abc"));           // Failure(Not a number: abc)

    // map: transform success
    String formatted = parseInt("42")
        .map(n -> "Number: " + n)
        .orElse("Invalid");
    System.out.println(formatted);  // Number: 42

    String failed = parseInt("abc")
        .map(n -> "Number: " + n)
        .orElse("Invalid");
    System.out.println(failed);  // Invalid
}
```

worked_example.final_code:
import java.util.function.Function;

public class Result<T> {
    private final T value;
    private final String error;
    private final boolean success;

    private Result(T value, String error, boolean success) {
        this.value=value; this.error=error; this.success=success;
    }

    public static <T> Result<T> success(T value)    { return new Result<>(value, null,  true); }
    public static <T> Result<T> failure(String err) { return new Result<>(null,  err,   false); }

    public boolean isSuccess() { return success; }
    public T getValue()  {
        if (!success) throw new IllegalStateException("Failure: " + error);
        return value;
    }
    public String getError() { return error; }
    public T orElse(T def)   { return success ? value : def; }

    public <R> Result<R> map(Function<T, R> mapper) {
        return success ? Result.success(mapper.apply(value)) : Result.failure(error);
    }

    public String toString() { return success ? "Success(" + value + ")" : "Failure(" + error + ")"; }

    static Result<Integer> safeDivide(int a, int b) {
        return b == 0 ? Result.failure("Division by zero") : Result.success(a / b);
    }

    static Result<Integer> parseIntSafe(String s) {
        try { return Result.success(Integer.parseInt(s)); }
        catch (NumberFormatException e) { return Result.failure("Not a number: " + s); }
    }

    public static void main(String[] args) {
        System.out.println(safeDivide(10, 2));
        System.out.println(safeDivide(10, 0));
        System.out.println(parseIntSafe("42"));
        System.out.println(parseIntSafe("abc"));
        System.out.println(parseIntSafe("42").map(n -> "Value: " + n).orElse("Invalid"));
        System.out.println(parseIntSafe("abc").map(n -> "Value: " + n).orElse("Invalid"));
    }
}

